#include<bits/stdc++.h>
using namespace std;
bool a[10000001];
long long b[10000001], n, k = 0, f, c[100001],num=0;
int main() {
	cin>>f;
	cin>>n;

	
	for (long long i = f; i <= n; i++) {
		if(i==1||i==0) continue;
		if (!a[i]) {
			b[k++] = i;
			num++;
		}
		for (long long j = 0; j <= k ; j++) {
			a[b[j]*i] = 1;
			if (i % b[j] == 0) {
				break;
			}
		}
	}cout<<num;
	


}
